import React, { useState } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';

const COMPLAINT_TYPES = [
    { value: 'spam', label: 'Спам', emoji: '📧' },
    { value: 'violence', label: 'Насилие', emoji: '💢' },
    { value: 'harassment', label: 'Домогательство', emoji: '😡' },
    { value: 'copyright', label: 'Нарушение авторских прав', emoji: '©️' },
    { value: 'inappropriate', label: 'Неприемлемый контент', emoji: '🚫' },
    { value: 'other', label: 'Другое', emoji: '📝' },
];

export default function ComplaintModal({ videoId, onClose }) {
    const [complaintType, setComplaintType] = useState('');
    const [description, setDescription] = useState('');
    const [submitting, setSubmitting] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!complaintType) {
            toast.error('Выберите тип жалобы');
            return;
        }

        setSubmitting(true);
        try {
            const token = localStorage.getItem('access_token');
            await axios.post(
                `/videos/${videoId}/complaint/`,
                { complaint_type: complaintType, description },
                { headers: { 'Authorization': `Bearer ${token}` } }
            );
            toast.success('Жалоба отправлена администрации');
            onClose();
        } catch (error) {
            console.error('Error submitting complaint:', error);
            toast.error(error.response?.data?.error || 'Ошибка отправки жалобы');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50">
            <div className="bg-gray-900 rounded-xl p-6 max-w-md w-full">
                <h2 className="text-xl font-bold text-white mb-4">Пожаловаться на видео</h2>
                <form onSubmit={handleSubmit}>
                    <div className="mb-4">
                        <label className="block text-gray-300 mb-2">Тип жалобы</label>
                        <select
                            value={complaintType}
                            onChange={(e) => setComplaintType(e.target.value)}
                            className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white"
                            required
                        >
                            <option value="">Выберите...</option>
                            {COMPLAINT_TYPES.map(type => (
                                <option key={type.value} value={type.value}>
                                    {type.emoji} {type.label}
                                </option>
                            ))}
                        </select>
                    </div>
                    <div className="mb-4">
                        <label className="block text-gray-300 mb-2">Описание (необязательно)</label>
                        <textarea
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            rows="3"
                            className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white"
                            placeholder="Опишите подробнее..."
                        />
                    </div>
                    <div className="flex gap-3">
                        <button
                            type="submit"
                            disabled={submitting}
                            className="flex-1 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition disabled:opacity-50"
                        >
                            {submitting ? 'Отправка...' : 'Отправить жалобу'}
                        </button>
                        <button
                            type="button"
                            onClick={onClose}
                            className="flex-1 px-4 py-2 bg-gray-700 text-white rounded-lg hover:bg-gray-600 transition"
                        >
                            Отмена
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}
